/* Oct.01.2024 query AS400 option 1246 hold and serial numbers in whse 335  */
SELECT T1.*, B1.*
FROM (SELECT * FROM MasterData_ItemMaster_AFI.DWHOLDITM1 AS a
               WHERE a.ITEMNO IN ('1800412', '1800512', '4710212', '4710312')) AS T1
LEFT JOIN
(
    SELECT
    CAST(T1.TDTAG# AS VARCHAR(255)) AS SN,
    T1.TDITEM,
    T1.TDAPO#,
    T1.TDPDAT,
    T1.TDTSTS,
    T1.TDWHSE,
    CONCAT(T1.TDAREA, T1.TDASLE, T1.TDSEC, T1.TDTIER) AS LOCATION
FROM Manufacturing_Inventory_AFI.TAGINVD AS T1
WHERE T1.TDWHSE = '335'
  AND T1.TDTSTS IN ('R')
--   AND T1.TDITEM IN ('1800412', '1800512', '4710212', '4710312')
  AND EXISTS (
      SELECT 1
      FROM (SELECT '1800412' AS ItemNo
            UNION ALL
            SELECT '1800512'
            UNION ALL
            SELECT '4710212'
            UNION ALL
            SELECT '4710312') AS Items
      WHERE Items.ItemNo = T1.TDITEM
  )
) AS B1
ON T1.ITEMNO = B1.TDITEM AND T1.PONMON = B1.TDAPO#


/* to get rid of Ashton hold but exists in US whse  item_number	po_number
   -----DB2 VERSION
SELECT T1.*, B1.*
FROM DISTLIB.DWHOLDITM AS T1
LEFT JOIN
(
    SELECT
        CAST(T1.TDTAG# AS VARCHAR(255)) AS SN,
        T1.TDITEM,
        T1.TDAPO#,
        T1.TDPDAT,
        T1.TDTSTS,
        T1.TDWHSE,
        T1.TDAREA || T1.TDASLE || T1.TDSEC || T1.TDTIER AS LOCATION
    FROM DISTLIB.TAGINVD AS T1
    WHERE T1.TDWHSE = '335' AND T1.TDTSTS IN ('R')
) AS B1
ON T1.ITEMNO = B1.TDITEM AND T1.PONMON = B1.TDAPO#
WHERE T1.ITEMNO IN ('1800412', '1800512', '4710212', '4710312')


