SELECT t1.item_number, t1.po_number, t1.serial_number,  t1.wh_id 
FROM Distribution_Warehouse_Wholesale.t_serial_active  AS T1
WHERE  t1.serial_no_status NOT IN ('O') and t1.master_status NOT IN ('S')
AND T1.item_number IN ('3800648','3800656','3800655') AND T1.po_number IN ('P2D4B36','P2D9819','P2DVR03','P2DVT22','P2D9L51','P2DNR25')

